const express = require('express');
const bodyParser = require('body-parser');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.urlencoded({ extended: true }));

// Twilio configuration
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const twilioPhoneNumber = 'your_twilio_phone_number';

const client = new twilio(accountSid, authToken);

// In-memory storage for verification codes
const verificationCodes = {};

app.get('/send-sms', (req, res) => {
    const { phoneNumber } = req.query;
    if (!phoneNumber) {
        return res.status(400).json({ error: 'Phone number is required' });
    }

    // Generate a 6-digit random code
    const verificationCode = Math.floor(100000 + Math.random() * 900000);

    // Store the code in memory with an expiration time (e.g., 2 minutes)
    verificationCodes[phoneNumber] = {
        code: verificationCode,
        expiresAt: Date.now() + 120000
    };

    // Send the SMS with the verification code
    client.messages.create({
        body: `Your verification code is ${verificationCode}`,
        from: twilioPhoneNumber,
        to: phoneNumber
    }).then(message => {
        res.status(200).json({ message: 'Verification code sent' });
    }).catch(error => {
        res.status(500).json({ error: 'Failed to send SMS' });
    });
});

app.post('/verify-code', (req, res) => {
    const { phoneNumber, code } = req.body;
    if (!phoneNumber || !code) {
        return res.status(400).json({ error: 'Phone number and code are required' });
    }

    // Check if the verification code exists and is not expired
    const storedCodeInfo = verificationCodes[phoneNumber];
    if (storedCodeInfo && storedCodeInfo.code === parseInt(code, 10) && Date.now() < storedCodeInfo.expiresAt) {
        delete verificationCodes[phoneNumber]; // Remove the code after successful verification
        res.status(200).json({ message: 'Verification successful' });
    } else {
        res.status(400).json({ error: 'Invalid or expired verification code' });
    }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});